<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> semaphore </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> Arc</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">Semaphore</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;">MAX_CONCURRENT</span><span style="color:#9399B2;">));</span></span>
